class Solution:
    def maxOperations(self, nums):
        if len(nums) < 2:
            return 0
        target = nums[0] + nums[1]
        count = 0
        i = 0
        while i + 1 < len(nums):
            if nums[i] + nums[i+1] == target:
                count += 1
                i += 2
            else:
                break
        return count

